comments.body:
The podman version is :
[root@centos8 libpod]# ./bin/podman version
Client:       Podman Engine
Version:      4.0.0-dev
API Version:  4.0.0-dev
Go Version:   go1.17.7
Git Commit:   a88ea2c68b1ef01077a53b1c568b85667dcbc1e2
Built:        Tue Feb 22 04:02:18 2022
OS/Arch:      linux/amd64
[root@centos8 libpod]#

I use CNI, config file as following:
{
   "args": {
      "podman_options": {
         "mode": "bridge"
      }
   },
   "cniVersion": "0.4.0",
   "name": "ens192",
   "plugins": [
      {
         "type": "macvlan",
         "master": "ens192",
         "ipam": {
            "type": "host-local",
            "routes": [
               {
                  "dst": "0.0.0.0/0"
               }
            ],
            "ranges": [
               [
                  {
                     "subnet": "192.168.1.0/24",
                     "gateway": "192.168.1.1"
                  }
               ]
            ]
         },
         "mode": "bridge",
         "capabilities": {
            "ips": true
         }
      }
   ]
}
